[
  {{#each (dataRaw 'timeslots')}}
    {{#if (eq serviceId (urlParam 'id'))}}
      {{#if (eq date (queryParam 'date'))}}
        {{#unless @first}},{{/unless}}
        {
          "id": "{{id}}",
          "serviceId": "{{serviceId}}",
          "date": "{{lookup this 'date'}}",
          "startTime": "{{lookup this 'startTime'}}",
          "endTime": "{{lookup this 'endTime'}}",
          "isAvailable": {{lookup this 'isAvailable'}}
        }
      {{/if}}
    {{/if}}
  {{/each}}
]

